# class plane 

class Plane: 
       def __init__(self, start_pos, callsign):
              self.callsign = callsign
              self.grid_position = start_pos
              self.path = []
              self.index = 0 
              self.finished = False 
              self.speed = 0.2 # pizels per frame
              self.image = pygame.image.load("myFavplane.png").convert_alpha()
              if not isinstance(start_pos, (list, tuple)) or len(start_pos) != 2:
                     raise ValueError(f"value must not irfgaeiurgbqa got{start_pos}")
              
              # start at first tile center 
              x, y = start_pos
              self.x = x * TILE_SIZE + TILE_SIZE //2 
              self.y = y * TILE_SIZE + TILE_SIZE //2 

              # assert statements: 
              # i will use the assert statements to check if the data passed is correct or not: 
              assert plane.callsign == "speedbird123"
              assert plane.grid_position == [45,48]
              assert plane.index == 0 
              assert plane.path == [] 
              assert plane.speed == 0.2
              assert plane.finished == False  
       def update(self): 
              # stops when the plane reaches the end of the path
              if self.index >= len(self.path) - 1: 
                     self.finished = True 
                     print("path finished")
                     return # stops at the end 
              
              # setting x y coords to path 
              target_x, target_y = self.path[self.index + 1]
              target_x = target_x * TILE_SIZE + TILE_SIZE //2 
              target_y = target_y * TILE_SIZE + TILE_SIZE //2

              print(self.index) 
              #distance of coordinates minus the current position 
              dx = target_x - self.x
              dy = target_y - self.y 
              distance = (dx**2 + dy**2) ** 0.5

              if distance < self.speed: 
                     self.index += 1 
              else: 
                     self.x += self.speed * dx / distance
                     self.y += self.speed * dy / distance

              if self.path:
                     self.grid_position = self.path.pop(0) #moves along path 
              print(self.index)
              
       
       def set_path(self, path): 
              self.path = path 
              self.index = 0 
              self.finished = False
              print("paset:", path)
              print(f"Plane {self.callsign} path set: {self.path}")


       def draw(self, screen): 
              rect = self.image.get_rect(center=(self.x, self.y))
              screen.blit(self.image, rect)

